const rows = $input.all().map(r => r.json);

if (!rows.length || !rows[0].id) {
  return [{ json: { has_leads: false } }];
}

const CONFIRM_BASE = 'https://norrai.app.n8n.cloud/webhook/nurture-prompt-confirm';
const TOKEN = '8F68D963-7060-4033-BD04-7593E4B203CB';

const agents = {};
for (const row of rows) {
  const key = row.agent_email;
  if (!agents[key]) {
    agents[key] = {
      agent_email: row.agent_email,
      agent_name:  row.agent_name  || '',
      leads: []
    };
  }
  agents[key].leads.push(row);
}

const results = [];
for (const data of Object.values(agents)) {
  const { agent_email, agent_name, leads } = data;
  const first_name = agent_name.split(' ')[0] || 'there';
  const n = leads.length;
  const today = new Date().toLocaleDateString('en-US', {
    timeZone: 'America/Chicago',
    month: 'long', day: 'numeric', year: 'numeric'
  });

  const lead_blocks = leads.map(lead => {
    const added = new Date(lead.created_at).toLocaleDateString('en-US', {
      timeZone: 'America/Chicago',
      month: 'short', day: 'numeric'
    });
    const meta = (typeof lead.metadata === 'string' ? JSON.parse(lead.metadata || '{}') : lead.metadata) || {};
    const parts = [`Added: ${added}`, `Source: ${lead.source || 'unknown'}`];
    if (meta.property_address) parts.push(meta.property_address);
    if (meta.price_range)       parts.push(meta.price_range);
    if (meta.beds)              parts.push(`${meta.beds}bd`);
    const details = parts.join(' &middot; ');
    const enroll_url = `${CONFIRM_BASE}?lead_id=${lead.id}&token=${TOKEN}`;
    const lead_name_escaped = (lead.lead_name || 'Unknown Lead').replace(/[<>&"]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;','"':'&quot;'}[c]));

    return `<tr><td style="padding:20px 0;border-top:1px solid #E5E4DE;"><p style="margin:0 0 4px;font-size:16px;font-weight:600;color:#0A0F1A;font-family:'Inter',sans-serif;">${lead_name_escaped}</p><p style="margin:0 0 14px;font-size:13px;color:#9EA3AA;font-family:'Inter',sans-serif;">${details}</p><a href="${enroll_url}" style="display:inline-block;background:#0A0F1A;color:#FAFAF7;text-decoration:none;padding:10px 20px;border-radius:6px;font-size:13px;font-weight:600;font-family:'Inter',sans-serif;">Enroll in Cold Nurture</a></td></tr>`;
  }).join('');

  const html_body = `<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="font-family:'Inter',sans-serif;background:#FAFAF7;margin:0;padding:0;"><div style="max-width:540px;margin:0 auto;padding:40px 24px;"><p style="font-size:11px;letter-spacing:0.15em;text-transform:uppercase;color:#9EA3AA;margin:0 0 24px;">Norr AI</p><h2 style="font-size:22px;font-weight:700;color:#0A0F1A;margin:0 0 8px;letter-spacing:-0.02em;">Hi ${first_name},</h2><p style="font-size:15px;color:#3A3F48;margin:0 0 28px;line-height:1.6;">These leads received your first message but haven't been enrolled in your follow-up sequence yet. One click to enroll:</p><table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;">${lead_blocks}</table><p style="font-size:13px;color:#9EA3AA;margin:32px 0 0;line-height:1.6;">If you're already in conversation with someone, ignore their button — it will expire once they're enrolled or marked inactive.</p><p style="font-size:13px;color:#9EA3AA;margin:16px 0 0;">— Norr AI</p></div></body></html>`;

  results.push({ json: {
    has_leads:   true,
    to_email:    agent_email,
    subject:     `\uD83D\uDD14 ${n} lead${n > 1 ? 's' : ''} ready for nurture \u2014 ${today}`,
    html_body,
    lead_count:  n,
    agent_name
  }});
}

return results;
